import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withFirstRecordAsHeader();

        // The result should not be the same instance as the original
        assertNotSame(format, result);

        // The result should have header set (not null and length 0)
        assertNotNull(result.getHeader());
        assertEquals(0, result.getHeader().length);

        // The result should have skipHeaderRecord true
        assertTrue(result.getSkipHeaderRecord());

        // The original format should remain unchanged
        // Note: DEFAULT has header == null and skipHeaderRecord == false
        assertNull(format.getHeader());
        assertFalse(format.getSkipHeaderRecord());
    }
}
